/**
 * Asap Font for jsPDF
 * Auto-generated from Google Fonts TTF files
 * Regular (400) and Bold (700) weights
 */

// Asap Regular (400)
export const ASAP_REGULAR_BASE64 = '';

// Asap Bold (700)
export const ASAP_BOLD_BASE64 = '';

/**
 * Register Asap fonts with jsPDF document
 */
export const registerAsapFont = (doc: import('jspdf').jsPDF): void => {
  // Add Regular
  doc.addFileToVFS('Asap-Regular.ttf', ASAP_REGULAR_BASE64);
  doc.addFont('Asap-Regular.ttf', 'Asap', 'normal');
  
  // Add Bold
  doc.addFileToVFS('Asap-Bold.ttf', ASAP_BOLD_BASE64);
  doc.addFont('Asap-Bold.ttf', 'Asap', 'bold');
};
